return [
  {
    json: {
      rss_items: items.map(item => ({
        title: item.json.title ?? "",
        link: item.json.link ?? "",
        pubDate: item.json.pubDate ?? "",
        creator: item.json.creator ?? item.json["dc:creator"] ?? "",
        contentSnippet: item.json.contentSnippet ?? "",
        content: item.json.content ?? "",
        categories: item.json.categories ?? []
      }))
    }
  }
];

const inputItems = $json["rss_items"] || [];

if (!Array.isArray(inputItems)) {
  throw new Error("rss_items must be an array");
}

const seenLinks = new Set();
const seenTitles = new Set();
const cleaned = [];

function normalizeTitle(title) {
  return (title || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function extractDomain(url) {
  try {
    return new URL(url).hostname.replace("www.", "");
  } catch {
    return "unknown";
  }
}

for (let i = 0; i < inputItems.length; i++) {
  const item = inputItems[i];

  const title = (item.title || "").trim();
  const link = (item.link || "").trim();

  if (!title || !link) continue;

  if (seenLinks.has(link)) continue;
  seenLinks.add(link);

  const normTitle = normalizeTitle(title);
  if (seenTitles.has(normTitle)) continue;
  seenTitles.add(normTitle);

  const spamPatterns = ["subscribe", "sponsored", "advertisement", "promo"];
  const isSpam = spamPatterns.some(p => title.toLowerCase().includes(p));
  if (isSpam) continue;

  const cleanedItem = {
    id: `rss_${i}_${Date.now()}`,
    title,
    link,
    source: item.source || extractDomain(link),
    date: item.date || item.pubDate || null,
    creator: item.creator || "",
    contentSnippet: item.contentSnippet || "",
    content: item.content || "",
    categories: Array.isArray(item.categories) ? item.categories : [],
    source_domain: extractDomain(link),
    ingested_at: new Date().toISOString(),
    raw_index: i,
  };

  cleaned.push(cleanedItem);
}

return [
  {
    json: {
      rss_items: cleaned,
      input_count: inputItems.length,
      cleaned_count: cleaned.length,
      removed_count: inputItems.length - cleaned.length,
      checkpoint: "A0_input_guardrail",
      status: cleaned.length ? "pass" : "fail",
    },
  },
];

// Guardrail_A0_Output
const rawAgentOutput = $input.all()[0]?.json ?? {};

// Handle possible nesting under "output"
const agentOutput = rawAgentOutput.output ?? rawAgentOutput;

// Pull cleaned RSS items from Guardrail_A0_Input
const guardrailInputNode = $("Guardrail_A0_Input").first().json;
const rssItems = guardrailInputNode.rss_items || [];

if (!Array.isArray(rssItems)) {
  throw new Error("Guardrail_A0_Input.rss_items is missing or not an array");
}

const selected = agentOutput.selected_items;

// primary_story may be a string OR an object like { title, reason }
const primaryStoryRaw = agentOutput.primary_story;
const primaryStory =
  typeof primaryStoryRaw === "string"
    ? primaryStoryRaw
    : primaryStoryRaw?.title || "";

const articleThesis = agentOutput.article_thesis;
const suggestedTitle = agentOutput.suggested_newsletter_title;

const issues = [];
const warnings = [];
const checks = [];

function addCheck(check_id, result, details = "") {
  checks.push({ check_id, result, details });
}

function normalizeText(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function isNonEmptyString(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function isWeakText(value) {
  const text = String(value || "").trim();
  return !text || text.length < 20;
}

// Build allowed sets from input RSS
const allowedLinks = new Set();
const allowedTitles = new Set();

for (const item of rssItems) {
  if (item.link) allowedLinks.add(String(item.link).trim());
  if (item.title) allowedTitles.add(normalizeText(item.title));
}

// 1. selected_items structure
if (!Array.isArray(selected)) {
  issues.push("selected_items must be an array");
  addCheck("selected_items_array", "fail", "selected_items is missing or not an array");
} else {
  addCheck("selected_items_array", "pass");
}

const safeSelected = Array.isArray(selected) ? selected : [];

// 2. count check
if (safeSelected.length < 1) {
  issues.push("At least 1 selected item is required");
  addCheck("selected_count_min", "fail", `count=${safeSelected.length}`);
} else {
  addCheck("selected_count_min", "pass", `count=${safeSelected.length}`);
}

if (safeSelected.length > 5) {
  issues.push("selected_items cannot exceed 5 items");
  addCheck("selected_count_max", "fail", `count=${safeSelected.length}`);
} else {
  addCheck("selected_count_max", "pass", `count=${safeSelected.length}`);
}

// 3. top-level required fields
if (!isNonEmptyString(primaryStory)) {
  issues.push("primary_story is required");
  addCheck("primary_story_present", "fail");
} else {
  addCheck("primary_story_present", "pass");
}

if (!isNonEmptyString(articleThesis)) {
  issues.push("article_thesis is required");
  addCheck("article_thesis_present", "fail");
} else {
  addCheck("article_thesis_present", "pass");
}

if (!isNonEmptyString(suggestedTitle)) {
  issues.push("suggested_newsletter_title is required");
  addCheck("suggested_newsletter_title_present", "fail");
} else {
  addCheck("suggested_newsletter_title_present", "pass");
}

// per-item validation stays the same...
// final return should store agentOutput, not rawAgentOutput
return [
  {
    json: {
      checkpoint: "A0_post_agent_output_guardrail",
      status: issues.length ? "fail" : warnings.length ? "warning" : "pass",
      risk_score: issues.length ? 0.4 : warnings.length ? 0.2 : 0.1,
      issues,
      warnings,
      checks,
      summary: {
        input_rss_count: rssItems.length,
        selected_count: safeSelected.length,
        issue_count: issues.length,
        warning_count: warnings.length
      },
      agent0_output_validated: agentOutput,
      checked_at: new Date().toISOString()
    }
  }
];

// Verification_A0
// Converts Guardrail_A0_Output into audit-style verification evidence

const guardrail = $json;

const status = guardrail.status || "fail";
const riskScore = Number(guardrail.risk_score ?? 0.9);
const issues = Array.isArray(guardrail.issues) ? guardrail.issues : [];
const warnings = Array.isArray(guardrail.warnings) ? guardrail.warnings : [];
const checks = Array.isArray(guardrail.checks) ? guardrail.checks : [];
const summary = guardrail.summary || {};
const validatedOutput = guardrail.agent0_output_validated || {};

function deriveSeverity(status, riskScore, issuesCount) {
  if (status === "fail" || riskScore >= 0.75 || issuesCount >= 3) return "high";
  if (status === "warning" || riskScore >= 0.35 || issuesCount >= 1) return "medium";
  return "low";
}

function deriveAction(status, severity) {
  if (status === "fail") return "block_and_retry_agent_0";
  if (status === "warning" && severity === "medium") return "continue_with_review_flag";
  if (status === "warning" && severity === "high") return "manual_review";
  return "continue";
}

function mapPolicies(issues, warnings, checks) {
  const mappings = [];

  const hasSchemaProblem =
    issues.some(x => x.includes("missing required field")) ||
    issues.some(x => x.includes("selected_items must be an array"));

  const hasDuplicateProblem =
    issues.some(x => x.toLowerCase().includes("duplicate"));

  const hasTraceabilityProblem =
    issues.some(x => x.includes("link not found in Guardrail_A0_Input")) ||
    issues.some(x => x.includes("primary_story does not match"));

  const hasRationaleWeakness =
    warnings.some(x => x.includes("why_it_matters is weak")) ||
    warnings.some(x => x.includes("newsletter_angle is weak")) ||
    warnings.some(x => x.includes("article_thesis looks too short"));

  // POL-NEWS-001: Story selection discipline
  mappings.push({
    policy_id: "POL-NEWS-001",
    control: "Story selection discipline",
    result: issues.length === 0 ? "pass" : "warning"
  });

  // POL-NEWS-002: Duplicate prevention
  mappings.push({
    policy_id: "POL-NEWS-002",
    control: "Duplicate story prevention",
    result: hasDuplicateProblem ? "fail" : "pass"
  });

  // POL-NEWS-003: Output schema completeness
  mappings.push({
    policy_id: "POL-NEWS-003",
    control: "Output schema completeness",
    result: hasSchemaProblem ? "fail" : "pass"
  });

  // POL-NEWS-004: Source traceability
  mappings.push({
    policy_id: "POL-NEWS-004",
    control: "Source traceability to input RSS",
    result: hasTraceabilityProblem ? "fail" : "pass"
  });

  // POL-NEWS-005: Editorial rationale quality
  mappings.push({
    policy_id: "POL-NEWS-005",
    control: "Editorial rationale quality",
    result: hasRationaleWeakness ? "warning" : "pass"
  });

  return mappings;
}

const severity = deriveSeverity(status, riskScore, issues.length);
const recommendedAction = deriveAction(status, severity);
const policyMapping = mapPolicies(issues, warnings, checks);

const controlResults = checks.map(check => ({
  check_id: check.check_id,
  result: check.result,
  details: check.details || ""
}));

const continuePipeline = status !== "fail";

const runId = `newsletter_${new Date().toISOString().replace(/[:.]/g, "-")}`;

return [
  {
    json: {
      run_id: runId,
      checkpoint: "Verification_A0",
      agent: "Agent 0 - News Scout",
      verification_status: status,
      risk_score: riskScore,
      severity: severity,
      recommended_action: recommendedAction,
      continue_pipeline: continuePipeline,

      counts: {
        input_rss_count: summary.input_rss_count ?? 0,
        selected_count: summary.selected_count ?? 0,
        issue_count: summary.issue_count ?? issues.length,
        warning_count: summary.warning_count ?? warnings.length
      },

      issues: issues,
      warnings: warnings,
      control_results: controlResults,
      policy_mapping: policyMapping,

      evidence: {
        primary_story: validatedOutput.primary_story || null,
        article_thesis: validatedOutput.article_thesis || null,
        suggested_newsletter_title: validatedOutput.suggested_newsletter_title || null,
        selected_items: validatedOutput.selected_items || []
      },

      verified_at: new Date().toISOString()
    }
  }
];

// Guardrail_A1_Output
// Validates Agent 1 draft output against Verification_A0 evidence

const agentOutput = $input.all()[0]?.json ?? {};
const verificationA0 = $("Verification_A0").first().json;

const selectedStories = verificationA0?.evidence?.selected_items || [];
const allowedLinks = new Set(
  selectedStories.map(x => String(x.link || "").trim()).filter(Boolean)
);

const issues = [];
const warnings = [];
const checks = [];

function addCheck(check_id, result, details = "") {
  checks.push({ check_id, result, details });
}

function isNonEmptyString(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function isWeakText(value, min = 40) {
  return !isNonEmptyString(value) || String(value).trim().length < min;
}

function extractUrls(text) {
  const matches = String(text || "").match(/https?:\/\/[^\s)]+/g);
  return matches || [];
}

const title = agentOutput.title;
const summary = agentOutput.summary;
const article = agentOutput.article;
const keyTakeaways = agentOutput.key_takeaways;
const linkedinTeaser = agentOutput.linkedin_teaser;
const storyTrace = agentOutput.story_trace;

// 1. required top-level fields
if (!isNonEmptyString(title)) {
  issues.push("title is required");
  addCheck("title_present", "fail");
} else {
  addCheck("title_present", "pass");
}

if (!isNonEmptyString(summary)) {
  issues.push("summary is required");
  addCheck("summary_present", "fail");
} else {
  addCheck("summary_present", "pass");
  if (isWeakText(summary, 30)) {
    warnings.push("summary looks too short");
    addCheck("summary_strength", "warning", `length=${String(summary).trim().length}`);
  } else {
    addCheck("summary_strength", "pass", `length=${String(summary).trim().length}`);
  }
}

if (!isNonEmptyString(article)) {
  issues.push("article is required");
  addCheck("article_present", "fail");
} else {
  addCheck("article_present", "pass");
  if (isWeakText(article, 200)) {
    warnings.push("article looks too short");
    addCheck("article_strength", "warning", `length=${String(article).trim().length}`);
  } else {
    addCheck("article_strength", "pass", `length=${String(article).trim().length}`);
  }
}

if (!Array.isArray(keyTakeaways)) {
  issues.push("key_takeaways must be an array");
  addCheck("key_takeaways_array", "fail");
} else {
  addCheck("key_takeaways_array", "pass");
  if (keyTakeaways.length < 2) {
    warnings.push("key_takeaways has fewer than 2 items");
    addCheck("key_takeaways_count", "warning", `count=${keyTakeaways.length}`);
  } else {
    addCheck("key_takeaways_count", "pass", `count=${keyTakeaways.length}`);
  }
}

if (!isNonEmptyString(linkedinTeaser)) {
  issues.push("linkedin_teaser is required");
  addCheck("linkedin_teaser_present", "fail");
} else {
  addCheck("linkedin_teaser_present", "pass");
}

if (!Array.isArray(storyTrace)) {
  issues.push("story_trace must be an array");
  addCheck("story_trace_array", "fail");
} else {
  addCheck("story_trace_array", "pass");
}

// 2. banned phrases
const bannedPhrases = [
  "fully compliant",
  "guaranteed safe",
  "guarantees safety",
  "proves safety",
  "zero risk",
  "completely safe"
];

const combinedText = [
  title,
  summary,
  article,
  linkedinTeaser,
  ...(Array.isArray(keyTakeaways) ? keyTakeaways : [])
].join(" \n ");

const foundBanned = bannedPhrases.filter(p =>
  combinedText.toLowerCase().includes(p)
);

if (foundBanned.length > 0) {
  issues.push(`Banned overclaim phrases found: ${foundBanned.join(", ")}`);
  addCheck("banned_phrase_scan", "fail", foundBanned.join(", "));
} else {
  addCheck("banned_phrase_scan", "pass");
}

// 3. link traceability
const urlsInArticle = extractUrls(combinedText);
const unsupportedUrls = urlsInArticle.filter(url => !allowedLinks.has(url));

if (unsupportedUrls.length > 0) {
  issues.push(`Unsupported URLs found in Agent 1 output: ${unsupportedUrls.join(", ")}`);
  addCheck("output_url_traceability", "fail", unsupportedUrls.join(", "));
} else {
  addCheck("output_url_traceability", "pass");
}

// 4. story_trace link checks
if (Array.isArray(storyTrace)) {
  for (let i = 0; i < storyTrace.length; i++) {
    const item = storyTrace[i] || {};
    const idx = i + 1;

    if (!isNonEmptyString(item.title)) {
      issues.push(`story_trace item ${idx} missing title`);
    }

    const link = String(item.link || "").trim();
    if (!link) {
      issues.push(`story_trace item ${idx} missing link`);
    } else if (!allowedLinks.has(link)) {
      issues.push(`story_trace item ${idx} link is not from Agent 0 selected stories`);
    }
  }
}

// 5. key takeaway quality
if (Array.isArray(keyTakeaways)) {
  keyTakeaways.forEach((item, i) => {
    if (!isNonEmptyString(item)) {
      issues.push(`key_takeaways item ${i + 1} is empty`);
    } else if (String(item).trim().length < 15) {
      warnings.push(`key_takeaways item ${i + 1} looks too short`);
    }
  });
}

// 6. status
let status = "pass";
if (issues.length > 0) {
  status = "fail";
} else if (warnings.length > 0) {
  status = "warning";
}

let risk_score = 0.1;
risk_score += Math.min(issues.length * 0.12, 0.6);
risk_score += Math.min(warnings.length * 0.05, 0.2);
risk_score = Math.min(Number(risk_score.toFixed(2)), 0.95);

return [
  {
    json: {
      checkpoint: "A1_post_agent_output_guardrail",
      status,
      risk_score,
      issues,
      warnings,
      checks,
      summary: {
        selected_story_count: selectedStories.length,
        story_trace_count: Array.isArray(storyTrace) ? storyTrace.length : 0,
        issue_count: issues.length,
        warning_count: warnings.length
      },
      agent1_output_validated: agentOutput,
      checked_at: new Date().toISOString()
    }
  }
];

// Verification_A1
const guardrail = $json;

const status = guardrail.status || "fail";
const riskScore = Number(guardrail.risk_score ?? 0.9);
const issues = Array.isArray(guardrail.issues) ? guardrail.issues : [];
const warnings = Array.isArray(guardrail.warnings) ? guardrail.warnings : [];
const checks = Array.isArray(guardrail.checks) ? guardrail.checks : [];
const summary = guardrail.summary || {};
const validatedOutput = guardrail.agent1_output_validated || {};

function deriveSeverity(status, riskScore, issuesCount) {
  if (status === "fail" || riskScore >= 0.75 || issuesCount >= 3) return "high";
  if (status === "warning" || riskScore >= 0.35 || issuesCount >= 1) return "medium";
  return "low";
}

function deriveAction(status, severity) {
  if (status === "fail") return "block_and_retry_agent_1";
  if (status === "warning" && severity === "medium") return "continue_with_review_flag";
  if (status === "warning" && severity === "high") return "manual_review";
  return "continue";
}

const severity = deriveSeverity(status, riskScore, issues.length);
const recommendedAction = deriveAction(status, severity);
const continuePipeline = status !== "fail";

const controlResults = checks.map(check => ({
  check_id: check.check_id,
  result: check.result,
  details: check.details || ""
}));

const policyMapping = [
  {
    policy_id: "POL-NEWS-006",
    control: "Draft schema completeness",
    result: issues.some(x => x.includes("required") || x.includes("must be an array")) ? "fail" : "pass"
  },
  {
    policy_id: "POL-NEWS-007",
    control: "No unsupported source introduction",
    result: issues.some(x => x.includes("Unsupported URLs")) ? "fail" : "pass"
  },
  {
    policy_id: "POL-NEWS-008",
    control: "No editorial overclaiming",
    result: issues.some(x => x.includes("Banned overclaim phrases")) ? "fail" : "pass"
  },
  {
    policy_id: "POL-NEWS-009",
    control: "Traceability to selected stories",
    result: issues.some(x => x.includes("story_trace")) ? "fail" : "pass"
  },
  {
    policy_id: "POL-NEWS-010",
    control: "Newsletter draft quality",
    result: warnings.length > 0 ? "warning" : "pass"
  }
];

return [
  {
    json: {
      run_id: $("Verification_A0").first().json.run_id,
      checkpoint: "Verification_A1",
      agent: "Agent 1 - Draft Writer",
      verification_status: status,
      risk_score: riskScore,
      severity,
      recommended_action: recommendedAction,
      continue_pipeline: continuePipeline,
      counts: {
        selected_story_count: summary.selected_story_count ?? 0,
        story_trace_count: summary.story_trace_count ?? 0,
        issue_count: summary.issue_count ?? issues.length,
        warning_count: summary.warning_count ?? warnings.length
      },
      issues,
      warnings,
      control_results: controlResults,
      policy_mapping: policyMapping,
      evidence: {
        title: validatedOutput.title || null,
        summary: validatedOutput.summary || null,
        article: validatedOutput.article || null,
        key_takeaways: validatedOutput.key_takeaways || [],
        linkedin_teaser: validatedOutput.linkedin_teaser || null,
        story_trace: validatedOutput.story_trace || []
      },
      verified_at: new Date().toISOString()
    }
  }
];

// Guardrail_A2_Output
// Validates Reviewer Agent (Agent 2) output after Policy_Loader

const rawAgentOutput = $input.all()[0]?.json ?? {};
const agentOutput = rawAgentOutput.output ?? rawAgentOutput;

const issues = [];
const warnings = [];
const checks = [];

function addCheck(check_id, result, details = "") {
  checks.push({ check_id, result, details });
}

function isNonEmptyString(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function isValidArray(value) {
  return Array.isArray(value);
}

const allowedStatuses = ["approve", "revise", "escalate", "reject"];

const status = agentOutput.status;
const score = agentOutput.score;
const internalPolicyIssues = agentOutput.internal_policy_issues;
const governanceIssues = agentOutput.governance_issues;
const privacySecurityIssues = agentOutput.privacy_security_issues;
const missingCaveats = agentOutput.missing_caveats;
const requiredDisclosure = agentOutput.required_disclosure;
const recommendedEdits = agentOutput.recommended_edits;
const reviewSummary = agentOutput.review_summary;

// 1. required top-level fields
if (!isNonEmptyString(status)) {
  issues.push("status is required");
  addCheck("status_present", "fail");
} else if (!allowedStatuses.includes(status)) {
  issues.push(`status must be one of: ${allowedStatuses.join(", ")}`);
  addCheck("status_allowed", "fail", `status=${status}`);
} else {
  addCheck("status_allowed", "pass", `status=${status}`);
}

if (typeof score !== "number" || Number.isNaN(score)) {
  issues.push("score must be a number");
  addCheck("score_numeric", "fail");
} else {
  addCheck("score_numeric", "pass", `score=${score}`);
  if (score < 0 || score > 10) {
    warnings.push("score is outside recommended 0-10 range");
    addCheck("score_range", "warning", `score=${score}`);
  } else {
    addCheck("score_range", "pass", `score=${score}`);
  }
}

if (!isNonEmptyString(reviewSummary)) {
  issues.push("review_summary is required");
  addCheck("review_summary_present", "fail");
} else {
  addCheck("review_summary_present", "pass");
  if (reviewSummary.trim().length < 40) {
    warnings.push("review_summary looks too short");
    addCheck("review_summary_strength", "warning", `length=${reviewSummary.trim().length}`);
  } else {
    addCheck("review_summary_strength", "pass", `length=${reviewSummary.trim().length}`);
  }
}

// 2. required arrays
const arrayFields = [
  ["internal_policy_issues", internalPolicyIssues],
  ["governance_issues", governanceIssues],
  ["privacy_security_issues", privacySecurityIssues],
  ["missing_caveats", missingCaveats],
  ["required_disclosure", requiredDisclosure],
  ["recommended_edits", recommendedEdits]
];

for (const [fieldName, value] of arrayFields) {
  if (!isValidArray(value)) {
    issues.push(`${fieldName} must be an array`);
    addCheck(`${fieldName}_array`, "fail");
  } else {
    addCheck(`${fieldName}_array`, "pass", `count=${value.length}`);
  }
}

// safe arrays
const safeInternalPolicyIssues = Array.isArray(internalPolicyIssues) ? internalPolicyIssues : [];
const safeGovernanceIssues = Array.isArray(governanceIssues) ? governanceIssues : [];
const safePrivacySecurityIssues = Array.isArray(privacySecurityIssues) ? privacySecurityIssues : [];
const safeMissingCaveats = Array.isArray(missingCaveats) ? missingCaveats : [];
const safeRequiredDisclosure = Array.isArray(requiredDisclosure) ? requiredDisclosure : [];
const safeRecommendedEdits = Array.isArray(recommendedEdits) ? recommendedEdits : [];

const totalIssueCount =
  safeInternalPolicyIssues.length +
  safeGovernanceIssues.length +
  safePrivacySecurityIssues.length +
  safeMissingCaveats.length +
  safeRequiredDisclosure.length;

// 3. consistency checks
if (status === "approve") {
  if (totalIssueCount > 0 || safeRecommendedEdits.length > 0) {
    warnings.push("status is approve but issues or edits are still present");
    addCheck("approve_consistency", "warning", `issue_count=${totalIssueCount}, edits=${safeRecommendedEdits.length}`);
  } else {
    addCheck("approve_consistency", "pass");
  }
}

if (status === "reject") {
  if (totalIssueCount === 0 && safeRecommendedEdits.length === 0) {
    issues.push("status is reject but no issues or recommended edits were provided");
    addCheck("reject_consistency", "fail");
  } else {
    addCheck("reject_consistency", "pass", `issue_count=${totalIssueCount}, edits=${safeRecommendedEdits.length}`);
  }
}

if (status === "revise") {
  if (safeRecommendedEdits.length === 0) {
    warnings.push("status is revise but recommended_edits is empty");
    addCheck("revise_consistency", "warning");
  } else {
    addCheck("revise_consistency", "pass", `edits=${safeRecommendedEdits.length}`);
  }
}

if (status === "escalate") {
  if (totalIssueCount === 0) {
    warnings.push("status is escalate but no issue buckets contain findings");
    addCheck("escalate_consistency", "warning");
  } else {
    addCheck("escalate_consistency", "pass", `issue_count=${totalIssueCount}`);
  }
}

